@strawberry.type
class Query:
    @strawberry.field
    def product(self, info, id: int) -> ProductType:
        session = Session()
        product = session.query(Product).filter_by(id=id).first()
        return ProductType(
            id=product.id,
            name=product.name,
            reviews=[ReviewType(id=r.id, content=r.content) for r in product.reviews],
            sellers=[SellerType(id=s.id, name=s.name) for s in product.sellers],
            categories=[CategoryType(id=c.id, name=c.name) for c in product.categories],
            images=[ImageType(id=i.id, url=i.url) for i in product.images]
        )

